//! Post-lowering expansion stage.
//!
//! Base lowering ([`base_scope_graph_impl`]) turns the AST into HIR items and
//! the base scope graph. This module runs *after* that, synthesizing
//! additional HIR items from the lowered ones — the impls generated by
//! derive providers for `#[derive(..)]` attributes and `derive` declarations
//! — and producing a partial scope graph that
//! [`scope_graph_impl`](super::scope_graph_impl) merges into the base graph.
//! Downstream consumers (name resolution, `all_items`, type checking, MIR)
//! therefore see generated items exactly like hand-written ones, with no
//! special casing.
//!
//! Stratification: this stage may only depend on *base* scope graphs (and
//! analyses over base items); it must never read the merged
//! [`scope_graph_impl`](super::scope_graph_impl) query of any module of the
//! requesting ingot, which would form a cycle. Provider bodies are ordinary
//! base items (of this ingot or a dependency), and generated items never
//! feed back into generation: derive targets and providers are discovered
//! only among base items, and generated impls carry no derive markers.

use common::indexmap::{IndexMap, IndexSet};
use parser::ast::{self, prelude::*};
use rustc_hash::FxHashSet;
use salsa::Update;

use super::{
    FileLowerCtxt, base_scope_graph_impl,
    derive::{self, DeriveErrorKind, DeriveRequest, ProviderImplExpansion, accumulate_error},
    provider::{self, ProviderSelection},
    top_mod_ast,
};
use crate::{
    HirDb, LowerHirDb,
    hir_def::{
        DeriveDecl, Enum, IdentId, ItemKind, PathId, Struct, TopLevelMod, Trait,
        scope_graph::{EdgeKind, Scope, ScopeGraph, ScopeId},
    },
    span::{DeriveDesugared, DesugaredOrigin, HirOrigin},
};

/// The result of the post-lowering expansion stage for one top-level module.
#[derive(Debug, Clone, PartialEq, Eq, Update)]
pub struct ExpandedItems<'db> {
    /// The generated top-level items (the provider-generated `impl Trait`
    /// items), in deterministic base-DFS order.
    pub items: Vec<ItemKind<'db>>,
    /// Partial scope graph holding the generated items' scopes. Each
    /// generated item hangs off a shim node that mirrors an existing scope
    /// of the base graph (the lexical parent of the item it was derived
    /// from); merging unions the shim's edges into the base scope.
    pub(crate) graph: ScopeGraph<'db>,
}

/// Returns the HIR items synthesized for `top_mod` by the post-lowering
/// expansion stage, in deterministic order.
pub fn generated_hir_items<'db>(
    db: &'db dyn LowerHirDb,
    top_mod: TopLevelMod<'db>,
) -> &'db [ItemKind<'db>] {
    &expanded_items_impl(db, top_mod).items
}

/// A derive target: a base struct or enum, paired with its original AST
/// node (recovered through the item's `HirOrigin`) and the requests that
/// accumulated against it from `#[derive(..)]` attributes and `derive`
/// declarations.
enum TargetKind<'db> {
    Struct(Struct<'db>, ast::Struct),
    Enum(Enum<'db>, ast::Enum),
    /// A SYNTHETIC struct with no source `ast::Struct` — a `#[msg]` variant
    /// struct (FCO #5c). The compiler schedules a NAMED `AbiSize` derive for it;
    /// `lower_synthetic_struct_derives` reflects its HIR fields and uses the
    /// carried span as the (never-firing) generics-diagnostic anchor.
    SyntheticStruct(Struct<'db>, parser::TextRange),
}

struct PendingTarget<'db> {
    kind: TargetKind<'db>,
    requests: Vec<DeriveRequest<'db>>,
}

/// FCO S7: the `derived_pairs` conflict-detection key. Prefers the trait's
/// RESOLVED identity — exactly what `goal_matches_provider` (`provider.rs`)
/// selects providers by — over the raw last-segment ident, so an aliased
/// derive (`derive EqAlias for Foo` where `EqAlias` is
/// `use core::ops::Eq as EqAlias`) collides with a bare `derive Eq for Foo` /
/// `#[derive(Eq)]` for the SAME resolved trait, instead of silently bypassing
/// `ConflictingDerive` detection because the two spellings differ. Falls back
/// to the raw ident when the path does not resolve to a trait def from here
/// (an unrelated diagnostic, e.g. `UnknownTrait`/`UnresolvedDeclTarget`,
/// already covers that case elsewhere) — the fallback only preserves the
/// prior name-based behavior for it, never masking it. This is the
/// keystone-protective fix: `GeneratedImplTrait`'s content-keyed identity
/// (`core/hir_def/item.rs`) assumes at most one impl per (goal, self_ty); two
/// aliased derives bypassing this check would otherwise expand twice and
/// intern the same generated-impl id.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
enum DeriveConflictKey<'db> {
    Resolved(Trait<'db>),
    ByName(IdentId<'db>),
}

fn derive_conflict_key<'db>(
    db: &'db dyn HirDb,
    top_mod: TopLevelMod<'db>,
    trait_name: IdentId<'db>,
    trait_path: PathId<'db>,
) -> DeriveConflictKey<'db> {
    let canonical = provider::canonical_trait_path(db, top_mod, trait_path);
    match provider::resolve_trait_def(db, top_mod, canonical) {
        Some(trait_def) => DeriveConflictKey::Resolved(trait_def),
        None => DeriveConflictKey::ByName(trait_name),
    }
}

/// Runs the expansion stage for `top_mod`: collects derive requests from
/// `#[derive(..)]` attributes and `derive` declarations, executes the
/// selected providers, and synthesizes the resulting trait impls as real
/// HIR items. Derive diagnostics ([`DeriveError`](super::DeriveError) and
/// `#[default]` attribute misuse) are accumulated during this query's
/// execution.
#[salsa::tracked(return_ref)]
pub(crate) fn expanded_items_impl<'db>(
    db: &'db dyn HirDb,
    top_mod: TopLevelMod<'db>,
) -> ExpandedItems<'db> {
    let base = base_scope_graph_impl(db, top_mod);
    let root = top_mod_ast(db, top_mod).syntax().clone();

    let mut ctxt = FileLowerCtxt::enter_expansion(db, top_mod);

    // Derive targets in base-DFS order, with requests merged per item so
    // that attribute and declaration requests against the same target are
    // executed together (and validated together, e.g. `#[default]` variant
    // markers). Targets are grouped by the lexical parent scope of the
    // target item so the generated impls become siblings of it (resolving
    // unqualified references to the item and matching its visibility
    // context).
    let mut targets: IndexMap<ItemKind<'db>, PendingTarget<'db>> = IndexMap::new();
    let mut groups: IndexMap<ScopeId<'db>, Vec<ItemKind<'db>>> = IndexMap::new();
    // Every `(target item, trait)` pair scheduled for generation, used
    // to diagnose conflicts between `#[derive(..)]` attributes and
    // standalone `derive` declarations (and between identical declarations).
    // Keyed on resolved trait identity, not spelling — see
    // `DeriveConflictKey`.
    let mut derived_pairs: IndexSet<(ItemKind<'db>, DeriveConflictKey<'db>)> = IndexSet::new();
    // Enums that did not become derive targets still need their
    // `#[default]` markers diagnosed as misplaced. Whether an enum is a
    // target is only known after the declaration walk, so collect them
    // here and filter at reporting time.
    let mut other_enums: Vec<(ItemKind<'db>, ast::Enum)> = Vec::new();

    let schedule = |targets: &mut IndexMap<ItemKind<'db>, PendingTarget<'db>>,
                    groups: &mut IndexMap<ScopeId<'db>, Vec<ItemKind<'db>>>,
                    item: ItemKind<'db>,
                    kind: TargetKind<'db>,
                    request: DeriveRequest<'db>| {
        if let Some(pending) = targets.get_mut(&item) {
            pending.requests.push(request);
            return;
        }
        let Some(parent) = lex_parent(base, item) else {
            return;
        };
        groups.entry(parent).or_default().push(item);
        targets.insert(
            item,
            PendingTarget {
                kind,
                requests: vec![request],
            },
        );
    };

    // First walk: `#[derive(..)]`-annotated structs and enums contribute
    // attribute requests; derive provider declarations are shape-validated.
    for item in base.items_dfs(db) {
        match item {
            ItemKind::Struct(struct_) => match struct_.origin(db) {
                HirOrigin::Raw(ptr) => {
                    let Some(ast) = ptr
                        .syntax_node_ptr()
                        .try_to_node(&root)
                        .and_then(ast::Struct::cast)
                    else {
                        continue;
                    };
                    if !derive::has_derive_attr(&ast) {
                        continue;
                    }
                    let item_name = ast.name().map(|n| n.text().to_string());
                    let traits =
                        derive::parse_derive_traits(&mut ctxt, ast.attr_list(), &item_name);
                    let desugared = DeriveDesugared::Struct(parser::ast::AstPtr::new(&ast));
                    for (trait_name, range) in traits {
                        let trait_path = PathId::from_ident(db, trait_name);
                        derived_pairs.insert((
                            item,
                            derive_conflict_key(db, top_mod, trait_name, trait_path),
                        ));
                        schedule(
                            &mut targets,
                            &mut groups,
                            item,
                            TargetKind::Struct(struct_, ast.clone()),
                            DeriveRequest {
                                trait_name,
                                trait_path,
                                primary_range: range,
                                selection: ProviderSelection::Canonical,
                                selection_range: None,
                                desugared: desugared.clone(),
                            },
                        );
                    }
                }
                // `#[event]` / `#[error]` structs cannot be USER derive
                // targets; a `#[derive(..)]` on them is still reported.
                HirOrigin::Desugared(DesugaredOrigin::Event(_) | DesugaredOrigin::Error(_)) => {
                    report_derive_on_desugared_struct(&mut ctxt, struct_, &root);
                    // FCO #5b (Route A): the compiler itself schedules a
                    // synthetic, NAMED `AbiSize` derive for `#[error]`
                    // desugared structs, replacing the deleted Rust
                    // `lower_error_abi_size_impl` generator. This is
                    // compiler-internal — not a user `#[derive]` — so it runs
                    // regardless of the report above (a malformed user
                    // `#[derive]` on the error is independent of the synthetic
                    // AbiSize impl the error always needs).
                    if let HirOrigin::Desugared(DesugaredOrigin::Error(
                        crate::span::ErrorDesugared { error_struct },
                    )) = struct_.origin(db)
                    {
                        schedule_error_abi_size(
                            db,
                            ctxt.top_mod(),
                            struct_,
                            error_struct.clone(),
                            &mut |item, kind, request| {
                                schedule(&mut targets, &mut groups, item, kind, request)
                            },
                        );
                    }
                    continue;
                }
                // FCO #5c (Route A): a `#[msg]` block desugars to a mod of
                // per-variant structs. The compiler schedules a synthetic NAMED
                // `AbiSize` derive for each VARIANT struct, replacing the deleted
                // Rust `lower_msg_variant_abi_size_impl` generator. Variant
                // structs are fully synthetic (source is `ast::MsgVariant`, no
                // `ast::Struct`), so this uses a `SyntheticStruct` target. The
                // msg MOD itself (variant_idx == None) is not a struct target.
                HirOrigin::Desugared(DesugaredOrigin::Msg(_)) => {
                    if let HirOrigin::Desugared(DesugaredOrigin::Msg(crate::span::MsgDesugared {
                        msg,
                        variant_idx: Some(variant_idx),
                        ..
                    })) = struct_.origin(db)
                    {
                        schedule_msg_variant_abi_size(
                            db,
                            ctxt.top_mod(),
                            struct_,
                            msg.clone(),
                            *variant_idx,
                            &mut |item, kind, request| {
                                schedule(&mut targets, &mut groups, item, kind, request)
                            },
                        );
                    }
                    continue;
                }
                _ => continue,
            },
            ItemKind::Enum(enum_) => {
                let HirOrigin::Raw(ptr) = enum_.origin(db) else {
                    continue;
                };
                let Some(ast) = ptr
                    .syntax_node_ptr()
                    .try_to_node(&root)
                    .and_then(ast::Enum::cast)
                else {
                    continue;
                };
                if !derive::enum_has_derive_attr(&ast) {
                    other_enums.push((item, ast));
                    continue;
                }
                let item_name = ast.name().map(|n| n.text().to_string());
                let traits = derive::parse_derive_traits(&mut ctxt, ast.attr_list(), &item_name);
                if traits.is_empty() {
                    // A derive attribute with no valid argument: the enum is
                    // not a target (unless a declaration targets it), so
                    // validate its markers with the others.
                    other_enums.push((item, ast));
                    continue;
                }
                let desugared = DeriveDesugared::Enum(parser::ast::AstPtr::new(&ast));
                for (trait_name, range) in traits {
                    let trait_path = PathId::from_ident(db, trait_name);
                    derived_pairs.insert((
                        item,
                        derive_conflict_key(db, top_mod, trait_name, trait_path),
                    ));
                    schedule(
                        &mut targets,
                        &mut groups,
                        item,
                        TargetKind::Enum(enum_, ast.clone()),
                        DeriveRequest {
                            trait_name,
                            trait_path,
                            primary_range: range,
                            selection: ProviderSelection::Canonical,
                            selection_range: None,
                            desugared: desugared.clone(),
                        },
                    );
                }
            }
            ItemKind::ImplTrait(impl_trait)
                if provider::impl_trait_provider_goal_path(db, impl_trait).is_some() =>
            {
                // Shape-validate providers declared in this module so a
                // malformed provider is diagnosed even when nothing selects
                // it. (Providers of other modules are validated when their
                // own module expands.) A provider is the ordinary
                // `impl Derive<Goal> for Provider` form, recognized by the
                // trait ref's resolved `core::derive::Derive` identity.
                if let Err(errors) = provider::validate_impl_provider(db, impl_trait) {
                    let item_name = impl_trait
                        .type_ref(db)
                        .to_opt()
                        .map(|ty| ty.pretty_print(db));
                    for error in errors {
                        accumulate_error(
                            &mut ctxt,
                            &item_name,
                            DeriveErrorKind::InvalidProvider {
                                message: error.message,
                            },
                            error.range,
                        );
                    }
                }
            }
            _ => continue,
        }
    }

    // Second walk: standalone `derive Trait for Type` declarations
    // contribute further requests (canonical or `using`-selected).
    for item in base.items_dfs(db) {
        if let ItemKind::DeriveDecl(decl) = item {
            expand_derive_decl(
                db,
                &mut ctxt,
                base,
                &root,
                decl,
                &mut |item, kind, request| schedule(&mut targets, &mut groups, item, kind, request),
                &mut derived_pairs,
            );
        }
    }

    // Enums that are not derive targets: their `#[default]` markers are
    // misplaced. (Target enums — including ones targeted only by `derive`
    // declarations — are validated in `lower_enum_derives`, where the full
    // request set is known.)
    for (item, ast) in &other_enums {
        if !targets.contains_key(item) {
            derive::report_misplaced_default_attrs(&mut ctxt, ast);
        }
    }

    // Each generated impl is minted by the staged-generation query
    // (`expand_provider_impl`, in `derive`), which returns it as a self-contained
    // scope-graph fragment. Collect the fragments in base-DFS / request order
    // (`ctxt` still carries the request/target diagnostics), then merge them
    // into the expansion graph below.
    let mut fragments: Vec<&ProviderImplExpansion<'db>> = Vec::new();
    for (&parent, group_items) in &groups {
        let vis = base.scope_data(&parent).vis;
        for item in group_items {
            let Some(pending) = targets.get(item) else {
                continue;
            };
            match &pending.kind {
                TargetKind::Struct(struct_, ast) => {
                    derive::lower_struct_derives(
                        &mut ctxt,
                        parent,
                        vis,
                        ast,
                        *struct_,
                        &pending.requests,
                        &mut fragments,
                    );
                }
                TargetKind::Enum(enum_, ast) => {
                    derive::lower_enum_derives(
                        &mut ctxt,
                        parent,
                        vis,
                        ast,
                        *enum_,
                        &pending.requests,
                        &mut fragments,
                    );
                }
                TargetKind::SyntheticStruct(struct_, anchor) => {
                    derive::lower_synthetic_struct_derives(
                        &mut ctxt,
                        parent,
                        vis,
                        *anchor,
                        *struct_,
                        &pending.requests,
                        &mut fragments,
                    );
                }
            }
        }
    }

    // Merge the per-impl fragments into a single expansion graph. This
    // reproduces, byte-for-byte, the graph the inline single-context build
    // produced: fragments are visited in synthesis order, so per-impl scopes
    // are appended in the same order, and a shim mirroring a parent scope shared
    // by sibling impls unions its generated parent-to-child edges (exactly the
    // union `merged_scope_graph_impl` performs when merging into the base graph).
    let mut items = Vec::new();
    let mut scopes: IndexMap<ScopeId<'db>, Scope<'db>> = IndexMap::default();
    let mut unresolved_uses: FxHashSet<_> = FxHashSet::default();
    for fragment in fragments {
        let ProviderImplExpansion::Synthesized {
            items: frag_items,
            graph: frag_graph,
        } = fragment
        else {
            continue;
        };
        items.extend(frag_items.iter().copied());
        for (scope_id, scope) in &frag_graph.scopes {
            if let Some(existing) = scopes.get_mut(scope_id) {
                existing.edges.extend(scope.edges.iter().cloned());
            } else {
                scopes.insert(*scope_id, scope.clone());
            }
        }
        unresolved_uses.extend(frag_graph.unresolved_uses.iter().copied());
    }

    let graph = ScopeGraph {
        top_mod,
        scopes,
        unresolved_uses,
    };

    ExpandedItems { items, graph }
}

/// FCO #5b: schedules the compiler-internal, NAMED `AbiSize` derive request
/// for an `#[error]` desugared struct (Route A), replacing the deleted Rust
/// `lower_error_abi_size_impl` generator.
///
/// The request targets the `AbiSize` trait (canonical path `core::abi::AbiSize`,
/// spelled through the error module's own core-ingot alias so it resolves to the
/// real core trait def from any ingot), selected by NAME (`StableAbiSize`, the
/// std-resident provider). It carries a `DeriveDesugared::Struct` origin built
/// from the error struct's own AST, so the generated impl's origin is a
/// `Desugared(Derive(..))` — provenance (`derived_impl_provenance`) then
/// attributes it to `StableAbiSize`, and `lower_struct_derives` sources the
/// reflection from the error struct's HIR fields, exactly like a user
/// `derive AbiSize for E using StableAbiSize`.
fn schedule_error_abi_size<'db>(
    db: &'db dyn HirDb,
    top_mod: TopLevelMod<'db>,
    struct_: Struct<'db>,
    error_struct: parser::ast::AstPtr<ast::Struct>,
    schedule: &mut dyn FnMut(ItemKind<'db>, TargetKind<'db>, DeriveRequest<'db>),
) {
    use crate::hir_def::TypeKind;
    use common::ingot::IngotKind;

    // Well-formedness gate — byte-identical to the deleted Rust generator's
    // guards in `lower_error_struct`: the `AbiSize` impl was generated ONLY for
    // a named, non-generic error struct whose fields are all `Path` types
    // (`parse_error_fields` rejects non-`Path` fields, setting `is_valid =
    // false`, and the generator early-returns on `!is_valid`/generics/missing
    // name). Replicating it here keeps the negative fixtures' diagnostics
    // unchanged: a tuple/array field (`error_tuple_field`) still produces ONLY
    // its 16-0004 diagnostic, with no synthetic `AbiSize` impl scheduled.
    if struct_.name(db).to_opt().is_none() {
        return;
    }
    if !struct_.generic_params(db).data(db).is_empty() {
        return;
    }
    let fields = struct_.fields(db);
    for field in fields.data(db) {
        let Some(ty) = field.type_ref.to_opt() else {
            return;
        };
        if !matches!(ty.data(db), TypeKind::Path(_)) {
            return;
        }
        if field.name.to_opt().is_none() {
            return;
        }
    }

    // Recover the error struct's AST: `lower_struct_derives` uses it only for the
    // item name and the generic-params diagnostic range (error structs have no
    // generics). The reflection itself comes from the struct's HIR fields.
    let root = top_mod_ast(db, top_mod).syntax().clone();
    let Some(ast) = error_struct
        .syntax_node_ptr()
        .try_to_node(&root)
        .and_then(ast::Struct::cast)
    else {
        return;
    };

    // The core-ingot alias as seen from the error module: `ingot` when the error
    // itself lives in `core` (e.g. `core::error::*`), `core` otherwise. Mirrors
    // `LibRoots::for_ctxt`, so the synthetic goal path resolves to the real
    // `core::abi::AbiSize` trait def from this module (selection-by-identity).
    let core_alias = if top_mod.ingot(db).kind(db) == IngotKind::Core {
        IdentId::make_ingot(db)
    } else {
        IdentId::make_core(db)
    };
    let abi_size_ident = IdentId::new(db, "AbiSize".to_string());
    let trait_path = PathId::from_ident(db, core_alias)
        .push_ident(db, IdentId::new(db, "abi".to_string()))
        .push_ident(db, abi_size_ident);

    // NAMED selection of the std-resident `StableAbiSize` provider (a bare
    // ident — `select_provider`'s named path resolves it by provider name).
    let provider_path = PathId::from_ident(db, IdentId::new(db, "StableAbiSize".to_string()));

    let primary_range = ast.syntax().text_range();

    schedule(
        ItemKind::Struct(struct_),
        TargetKind::Struct(struct_, ast),
        DeriveRequest {
            trait_name: abi_size_ident,
            trait_path,
            primary_range,
            selection: ProviderSelection::Named(provider_path),
            selection_range: None,
            desugared: DeriveDesugared::Struct(error_struct),
        },
    );
}

/// FCO #5c: schedules the compiler-internal, NAMED `AbiSize` derive request for
/// a `#[msg]` VARIANT struct (Route A), replacing the deleted Rust
/// `lower_msg_variant_abi_size_impl` generator.
///
/// Unlike `#[error]` structs (which have a real source `ast::Struct`), msg
/// variant structs are FULLY SYNTHETIC — the source is an `ast::MsgVariant`, so
/// there is no `ast::Struct` to feed the normal `TargetKind::Struct` path. This
/// schedules a `TargetKind::SyntheticStruct` instead: `lower_synthetic_struct_
/// derives` reflects the variant struct's HIR fields and uses `anchor` (the
/// variant's span) only as the never-firing generics-diagnostic fallback. The
/// goal trait is the real `core::abi::AbiSize` (spelled through the module's
/// core-ingot alias), selected by NAME (`StableAbiSize`, the std-resident
/// provider). Provenance is `DeriveDesugared::MsgVariant(msg, idx)`.
///
/// No `#[error]`-style Path-field gate: the deleted msg generator emitted
/// `AbiSize` for every variant regardless of field shape, so a non-`AbiSize`
/// field now diagnoses through the generated impl exactly as it did before.
fn schedule_msg_variant_abi_size<'db>(
    db: &'db dyn HirDb,
    top_mod: TopLevelMod<'db>,
    struct_: Struct<'db>,
    msg: parser::ast::AstPtr<ast::Msg>,
    variant_idx: usize,
    schedule: &mut dyn FnMut(ItemKind<'db>, TargetKind<'db>, DeriveRequest<'db>),
) {
    use common::ingot::IngotKind;

    // Guard against a parser-error variant with no name (avoid a nameless impl).
    if struct_.name(db).to_opt().is_none() {
        return;
    }

    // Recover the variant's span as the diagnostic anchor for the synthetic
    // struct (it has no `ast::Struct`).
    let root = top_mod_ast(db, top_mod).syntax().clone();
    let Some(msg_ast) = msg
        .syntax_node_ptr()
        .try_to_node(&root)
        .and_then(ast::Msg::cast)
    else {
        return;
    };
    let anchor = msg_ast
        .variants()
        .and_then(|vs| vs.into_iter().nth(variant_idx))
        .map(|v| v.syntax().text_range())
        .unwrap_or_else(|| msg_ast.syntax().text_range());

    // Same core-ingot alias as the error scheduler: `ingot` when the msg lives
    // in `core`, `core` otherwise — so the synthetic goal resolves to the real
    // `core::abi::AbiSize` def from this module.
    let core_alias = if top_mod.ingot(db).kind(db) == IngotKind::Core {
        IdentId::make_ingot(db)
    } else {
        IdentId::make_core(db)
    };
    let abi_size_ident = IdentId::new(db, "AbiSize".to_string());
    let trait_path = PathId::from_ident(db, core_alias)
        .push_ident(db, IdentId::new(db, "abi".to_string()))
        .push_ident(db, abi_size_ident);

    let provider_path = PathId::from_ident(db, IdentId::new(db, "StableAbiSize".to_string()));

    schedule(
        ItemKind::Struct(struct_),
        TargetKind::SyntheticStruct(struct_, anchor),
        DeriveRequest {
            trait_name: abi_size_ident,
            trait_path,
            primary_range: anchor,
            selection: ProviderSelection::Named(provider_path),
            selection_range: None,
            desugared: DeriveDesugared::MsgVariant(msg, variant_idx),
        },
    );
}

/// Reports the `#[derive(..)]` attributes of an `#[event]` / `#[error]`
/// struct (which cannot be derive targets). The original AST is recovered
/// from the struct's desugared origin.
fn report_derive_on_desugared_struct<'db>(
    ctxt: &mut FileLowerCtxt<'db>,
    struct_: Struct<'db>,
    root: &parser::SyntaxNode,
) {
    let (HirOrigin::Desugared(DesugaredOrigin::Event(crate::span::EventDesugared {
        event_struct: ptr,
    }))
    | HirOrigin::Desugared(DesugaredOrigin::Error(crate::span::ErrorDesugared {
        error_struct: ptr,
    }))) = struct_.origin(ctxt.db())
    else {
        return;
    };
    let Some(ast) = ptr
        .syntax_node_ptr()
        .try_to_node(root)
        .and_then(ast::Struct::cast)
    else {
        return;
    };
    if derive::has_derive_attr(&ast) {
        derive::report_derive_on_event_or_error_struct(ctxt, &ast);
    }
}

/// Validates one standalone `derive Trait for Type` declaration and
/// schedules a request against its target. Declarations selecting a
/// provider — explicitly via `using Provider` or implicitly through an
/// enclosing `with Provider { .. }` scope — produce named-selection
/// requests; bare declarations select the canonical core provider.
fn expand_derive_decl<'db>(
    db: &'db dyn HirDb,
    ctxt: &mut FileLowerCtxt<'db>,
    base: &ScopeGraph<'db>,
    root: &parser::SyntaxNode,
    decl: DeriveDecl<'db>,
    schedule: &mut dyn FnMut(ItemKind<'db>, TargetKind<'db>, DeriveRequest<'db>),
    derived_pairs: &mut IndexSet<(ItemKind<'db>, DeriveConflictKey<'db>)>,
) {
    let HirOrigin::Raw(ptr) = decl.origin(db) else {
        return;
    };
    let Some(decl_ast) = ptr
        .syntax_node_ptr()
        .try_to_node(root)
        .and_then(ast::DeriveDecl::cast)
    else {
        return;
    };
    let item_name = decl
        .target_path(db)
        .to_opt()
        .map(|path| path.pretty_print(db));

    // Trait: a single-identifier path naming the trait to derive.
    let Some(head_path) = decl.head_path(db).to_opt() else {
        // Parser error: missing trait path, already reported.
        return;
    };
    if path_has_missing_segment(db, head_path) {
        // Parser error inside the path, already reported; avoid cascading
        // a bogus unknown-trait diagnostic on top of it.
        return;
    }
    let head_range = decl_ast
        .head_path()
        .map(|path| path.syntax().text_range())
        .unwrap_or_else(|| decl_ast.syntax().text_range());
    // The goal trait's last path segment, used for diagnostics, `Default`
    // handling, and `#[derive]`/declaration conflict deduplication. The full
    // `head_path` (bare, aliased, or qualified) drives provider *selection*
    // by resolved identity (W-C); a qualified head no longer bails here.
    let Some(trait_name) = head_path.ident(db).to_opt() else {
        // Parser error inside the head path's last segment, already handled
        // by `path_has_missing_segment` above.
        return;
    };

    // Selection: explicit `using ..` or an enclosing `with Provider { .. }`
    // scope select by provider name; bare declarations use the canonical
    // core provider — and validate the trait against the core set up front,
    // by resolved identity, like attribute derives do.
    let (selection, selection_range) = if let Some(provider_path) = decl
        .selected_provider_path(db)
        .and_then(|path| path.to_opt())
    {
        let range = decl_ast
            .provider_path()
            .map(|path| path.syntax().text_range())
            .unwrap_or(head_range);
        (ProviderSelection::Named(provider_path), Some(range))
    } else {
        if !provider::is_core_derivable(db, ctxt.top_mod(), head_path) {
            accumulate_error(
                ctxt,
                &item_name,
                DeriveErrorKind::UnknownTrait {
                    name: head_path.pretty_print(db),
                    available: provider::core_derivable_trait_names(db, ctxt.top_mod()),
                },
                head_range,
            );
            return;
        }
        (ProviderSelection::Canonical, None)
    };

    // Target: resolve against the base scope graph from the declaration's
    // lexical scope.
    let Some(target_path) = decl.target_path(db).to_opt() else {
        // Parser error: missing target path, already reported.
        return;
    };
    if path_has_missing_segment(db, target_path) {
        // Parser error inside the path, already reported; avoid cascading
        // a bogus unresolved-target diagnostic on top of it.
        return;
    }
    let Some(decl_parent) = lex_parent(base, ItemKind::DeriveDecl(decl)) else {
        return;
    };
    let target_pretty = target_path.pretty_print(db);
    let target_range = decl_ast
        .target_path()
        .map(|path| path.syntax().text_range())
        .unwrap_or_else(|| decl_ast.syntax().text_range());
    let Some(target_item) = resolve_decl_target(db, base, decl_parent, target_path) else {
        accumulate_error(
            ctxt,
            &item_name,
            DeriveErrorKind::UnresolvedDeclTarget {
                path: target_pretty,
            },
            target_range,
        );
        return;
    };

    let kind = match target_item {
        ItemKind::Struct(struct_) => match struct_.origin(db) {
            HirOrigin::Raw(ptr) => {
                let Some(ast) = ptr
                    .syntax_node_ptr()
                    .try_to_node(root)
                    .and_then(ast::Struct::cast)
                else {
                    return;
                };
                TargetKind::Struct(struct_, ast)
            }
            HirOrigin::Desugared(DesugaredOrigin::Event(_) | DesugaredOrigin::Error(_)) => {
                accumulate_error(
                    ctxt,
                    &item_name,
                    DeriveErrorKind::InvalidDeclTarget {
                        path: target_pretty,
                        actual: "`#[event]`/`#[error]` struct",
                    },
                    target_range,
                );
                return;
            }
            _ => return,
        },
        ItemKind::Enum(enum_) => {
            let HirOrigin::Raw(ptr) = enum_.origin(db) else {
                return;
            };
            let Some(ast) = ptr
                .syntax_node_ptr()
                .try_to_node(root)
                .and_then(ast::Enum::cast)
            else {
                return;
            };
            TargetKind::Enum(enum_, ast)
        }
        other => {
            accumulate_error(
                ctxt,
                &item_name,
                DeriveErrorKind::InvalidDeclTarget {
                    path: target_pretty,
                    actual: other.kind_name(),
                },
                target_range,
            );
            return;
        }
    };

    let conflict_key = derive_conflict_key(db, ctxt.top_mod(), trait_name, head_path);
    if !derived_pairs.insert((target_item, conflict_key)) {
        accumulate_error(
            ctxt,
            &item_name,
            DeriveErrorKind::ConflictingDerive {
                trait_name: trait_name.data(db).to_string(),
                target: target_pretty,
            },
            decl_ast.syntax().text_range(),
        );
        return;
    }

    // Generated impls become siblings of the *target* (not of the
    // declaration), exactly like attribute derives: the synthesized impl
    // self type names the target unqualified, so it must resolve in the
    // target's own lexical context.
    schedule(
        target_item,
        kind,
        DeriveRequest {
            trait_name,
            trait_path: head_path,
            primary_range: head_range,
            selection,
            selection_range,
            desugared: DeriveDesugared::Decl(parser::ast::AstPtr::new(&decl_ast)),
        },
    );
}

/// Resolves the target path of a standalone `derive` declaration against the
/// *base* scope graph. The full path resolver cannot be used here: it
/// queries the merged scope graph, which would cycle back into this stage.
///
/// Leading `self`/`super` segments navigate the module chain explicitly
/// (modules are not lexically transparent in Fe). Otherwise the first
/// segment is looked up along the lexical scope chain of the declaration;
/// the remaining segments descend through named module/type edges. This
/// covers targets declared anywhere in the same file (including nested
/// modules), but not imported or cross-file names — those are diagnosed as
/// unresolved by the caller.
fn resolve_decl_target<'db>(
    db: &'db dyn HirDb,
    graph: &ScopeGraph<'db>,
    start: ScopeId<'db>,
    path: PathId<'db>,
) -> Option<ItemKind<'db>> {
    // Flatten the path into its segment identifiers, root first. Generic
    // arguments are irrelevant for target lookup (the generated impl always
    // covers the target's own parameters) and qualified-type paths are not
    // supported.
    let mut segments = Vec::new();
    let mut cursor = Some(path);
    while let Some(p) = cursor {
        segments.push(p.ident(db).to_opt()?);
        cursor = p.parent(db);
    }
    segments.reverse();

    let mut segments = segments.into_iter().peekable();

    // Leading `self` / `super..` segments: navigate the module chain. The
    // declaration's lexical parent is already its enclosing module (decls
    // are item-level), so `self` resolves to `start`.
    let mut module_relative = false;
    let mut scope = start;
    if segments.peek().is_some_and(|seg| seg.is_self(db)) {
        segments.next();
        module_relative = true;
    } else {
        while segments.peek().is_some_and(|seg| seg.is_super(db)) {
            segments.next();
            module_relative = true;
            scope = super_dest(graph, scope)?;
        }
    }

    let mut resolved = if module_relative {
        scope
    } else {
        // First segment: search the lexical scope chain.
        let first = segments.next()?;
        loop {
            if let Some(dest) = named_edge_dest(graph, scope, first) {
                break dest;
            }
            scope = lex_parent_scope(graph, scope)?;
        }
    };

    // Remaining segments: descend through named edges.
    for segment in segments {
        resolved = named_edge_dest(graph, resolved, segment)?;
    }

    match resolved {
        // An edge may leave the file (e.g. `super` from the file's own top
        // module); only same-file items can be expanded by this stage.
        ScopeId::Item(item) if item.top_mod(db) == graph.top_mod => Some(item),
        _ => None,
    }
}

/// Whether any segment of `path` lost its identifier to a parser error.
fn path_has_missing_segment<'db>(db: &'db dyn HirDb, path: PathId<'db>) -> bool {
    let mut cursor = Some(path);
    while let Some(p) = cursor {
        if !p.ident(db).is_present() {
            return true;
        }
        cursor = p.parent(db);
    }
    false
}

/// The edges of `scope`, or `None` when `scope` does not belong to `graph`
/// (e.g. a destination in another file reached through a `super` edge).
/// Never panics, unlike [`ScopeGraph::edges`].
fn scope_edges<'db, 'a>(
    graph: &'a ScopeGraph<'db>,
    scope: ScopeId<'db>,
) -> impl Iterator<Item = &'a crate::hir_def::scope_graph::ScopeEdge<'db>> {
    graph
        .scopes
        .get(&scope)
        .into_iter()
        .flat_map(|data| data.edges.iter())
}

/// The destination of a named (module/type/trait/value) edge of `scope`
/// matching `ident`, if any. Trait and value edges are included so that a
/// declaration targeting e.g. a function is reported as an *invalid* target
/// (with its actual kind) rather than an unresolved one.
fn named_edge_dest<'db>(
    graph: &ScopeGraph<'db>,
    scope: ScopeId<'db>,
    ident: IdentId<'db>,
) -> Option<ScopeId<'db>> {
    scope_edges(graph, scope).find_map(|edge| match edge.kind {
        EdgeKind::Mod(m) if m.0 == ident => Some(edge.dest),
        EdgeKind::Type(t) if t.0 == ident => Some(edge.dest),
        EdgeKind::Trait(t) if t.0 == ident => Some(edge.dest),
        EdgeKind::Value(v) if v.0 == ident => Some(edge.dest),
        _ => None,
    })
}

/// The lexical parent scope of `item` in `graph`.
fn lex_parent<'db>(graph: &ScopeGraph<'db>, item: ItemKind<'db>) -> Option<ScopeId<'db>> {
    lex_parent_scope(graph, ScopeId::Item(item))
}

/// The lexical parent of `scope` in `graph`.
fn lex_parent_scope<'db>(graph: &ScopeGraph<'db>, scope: ScopeId<'db>) -> Option<ScopeId<'db>> {
    scope_edges(graph, scope)
        .find_map(|edge| matches!(edge.kind, EdgeKind::Lex(_)).then_some(edge.dest))
}

/// The destination of the `super` edge of `scope`, if any.
fn super_dest<'db>(graph: &ScopeGraph<'db>, scope: ScopeId<'db>) -> Option<ScopeId<'db>> {
    scope_edges(graph, scope)
        .find_map(|edge| matches!(edge.kind, EdgeKind::Super(_)).then_some(edge.dest))
}

#[cfg(test)]
mod tests {
    use crate::{
        hir_def::ItemKind,
        lower::{base_scope_graph_impl, generated_hir_items, map_file_to_mod, scope_graph},
        test_db::TestDb,
    };

    /// `#[derive(..)]` impls are synthesized by the post-lowering expansion
    /// stage: absent from the base scope graph, listed by
    /// [`generated_hir_items`], and present in the merged scope graph like
    /// ordinary items — including for items nested in inner modules.
    #[test]
    fn derive_impls_synthesized_in_expansion_stage() {
        let mut db = TestDb::default();
        let text = r#"
            #[derive(Eq, Default)]
            struct Point {
                x: u256,
                y: u256,
            }

            mod inner {
                #[derive(Eq)]
                pub enum Mode {
                    On,
                    Off,
                }
            }
        "#;
        let file = db.standalone_file(text);
        let top_mod = map_file_to_mod(&db, file);

        // Base lowering no longer synthesizes any derive impls.
        let base = base_scope_graph_impl(&db, top_mod);
        assert!(
            base.items_dfs(&db)
                .all(|item| !matches!(item, ItemKind::ImplTrait(_)))
        );

        // The expansion stage generates one impl per derived trait.
        let generated = generated_hir_items(&db, top_mod);
        assert_eq!(generated.len(), 3);
        assert!(
            generated
                .iter()
                .all(|item| matches!(item, ItemKind::ImplTrait(_)))
        );

        // The merged scope graph exposes the generated impls and their
        // methods (`eq`, `eq`, `default`) like ordinary items.
        let merged = scope_graph(&db, top_mod);
        let impls = merged
            .items_dfs(&db)
            .filter(|item| matches!(item, ItemKind::ImplTrait(_)))
            .count();
        assert_eq!(impls, 3);
        let funcs = merged
            .items_dfs(&db)
            .filter(|item| matches!(item, ItemKind::Func(_)))
            .count();
        assert_eq!(funcs, 3);
    }

    /// Standalone `derive Trait for Type` declarations expand through the
    /// same stage as attribute derives: the generated impls become siblings
    /// of the *target* (not the declaration), including for targets declared
    /// in nested modules of the same file.
    #[test]
    fn derive_decls_expand_like_attr_derives() {
        let mut db = TestDb::default();
        let text = r#"
            struct It {
                x: u256,
            }

            derive Eq for It
            derive Default for It

            mod inner {
                pub struct Boxed {
                    pub v: u256,
                }

                derive Eq for Boxed
            }

            derive Eq for inner::Sealed
            mod inner2 {
                pub struct Sealed {
                    pub v: u256,
                }
            }
            derive Eq for inner2::Sealed
        "#;
        let file = db.standalone_file(text);
        let top_mod = map_file_to_mod(&db, file);

        // Base lowering produces the decls as items but no impls.
        let base = base_scope_graph_impl(&db, top_mod);
        assert_eq!(
            base.items_dfs(&db)
                .filter(|item| matches!(item, ItemKind::DeriveDecl(_)))
                .count(),
            5
        );
        assert!(
            base.items_dfs(&db)
                .all(|item| !matches!(item, ItemKind::ImplTrait(_)))
        );

        // One impl per *resolvable* declaration: `inner::Sealed` does not
        // exist (diagnosed, not expanded), `inner2::Sealed` does.
        let generated = generated_hir_items(&db, top_mod);
        assert_eq!(generated.len(), 4);
        assert!(
            generated
                .iter()
                .all(|item| matches!(item, ItemKind::ImplTrait(_)))
        );

        // Merged graph exposes the generated impls and their methods
        // (`eq`, `default`, `eq`, `eq`) like ordinary items.
        let merged = scope_graph(&db, top_mod);
        let funcs = merged
            .items_dfs(&db)
            .filter(|item| matches!(item, ItemKind::Func(_)))
            .count();
        assert_eq!(funcs, 4);
    }
}
